css:
.hub{--hub:#2563eb;--hub2:#1d4ed8;--hub-soft:#eff6ff;--hub-ink:#0f172a;--hub-muted:#64748b;--hub-line:#e2e8f0;--hub-card:#fff;--hub-radius:16px;max-width:1140px;margin:0 auto;padding:0 16px 48px;font-family:system-ui,-apple-system,"Segoe UI",Roboto,sans-serif;font-size:16px;line-height:1.6;color:var(--hub-ink);background:linear-gradient(180deg,#f8fafc 0%,#fff 22%)}
.hub a{color:var(--hub)}
.hub-hero{background:linear-gradient(135deg,var(--hub-soft) 0%,#fff 55%,#e0f2fe 100%);border:1px solid var(--hub-line);border-radius:calc(var(--hub-radius) + 4px);padding:clamp(1.5rem,4vw,2.5rem);margin:0 0 1.25rem;box-shadow:0 12px 40px rgba(37,99,235,.08)}
.hub-hero__inner{display:grid;grid-template-columns:1fr 1fr;gap:clamp(1.25rem,3vw,2.5rem);align-items:center}
@media(max-width:900px){.hub-hero__inner{grid-template-columns:1fr}}
.hub-kicker{font-size:.72rem;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:var(--hub);margin:0 0 .5rem}
.hub-h1{font-size:clamp(1.65rem,4.2vw,2.35rem);font-weight:800;line-height:1.12;margin:0 0 .75rem;letter-spacing:-.02em;color:var(--hub-ink)}
.hub-lead{margin:0 0 1.25rem;color:var(--hub-muted);font-size:1rem;max-width:34rem;line-height:1.55}
.hub-hero__cta{display:flex;flex-wrap:wrap;gap:.6rem;margin-bottom:1rem}
.hub-btn{display:inline-flex;align-items:center;justify-content:center;padding:.7rem 1.35rem;border-radius:10px;font-weight:700;font-size:.92rem;text-decoration:none;transition:transform .15s,box-shadow .15s}
.hub-btn--primary{background:linear-gradient(180deg,var(--hub),var(--hub2));color:#fff;box-shadow:0 6px 20px rgba(37,99,235,.35)}
.hub-btn--primary:hover{transform:translateY(-2px);box-shadow:0 10px 28px rgba(37,99,235,.4)}
.hub-btn--ghost{border:2px solid var(--hub);color:var(--hub2);background:#fff}
.hub-btn--ghost:hover{background:var(--hub-soft)}
.hub-btn--light{background:#fff;color:var(--hub2);font-size:1rem;padding:.85rem 1.5rem}
.hub-trustline{display:flex;flex-wrap:wrap;gap:.5rem 1rem;list-style:none;padding:0;margin:0;font-size:.8rem;font-weight:600;color:var(--hub-muted)}
.hub-trustline li{padding-left:1rem;position:relative}
.hub-trustline li::before{content:"";position:absolute;left:0;top:.45em;width:6px;height:6px;border-radius:50%;background:var(--hub)}
.hub-apgrid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;max-width:360px;margin:0 auto}
.hub-apgrid--5 .hub-apico:nth-child(4){grid-column:1}
.hub-apgrid--5 .hub-apico:nth-child(5){grid-column:2/span 2}
@media(min-width:901px){.hub-apgrid{margin:0 0 0 auto}}
.hub-apico{display:flex;flex-direction:column;align-items:center;gap:6px;padding:12px 8px;background:var(--hub-card);border:1px solid var(--hub-line);border-radius:12px;text-decoration:none;color:var(--hub-ink);font-size:.72rem;font-weight:700;text-align:center;transition:box-shadow .2s,border-color .2s,transform .2s}
.hub-apico:hover{border-color:var(--hub);box-shadow:0 8px 24px rgba(37,99,235,.12);transform:translateY(-2px)}
.hub-apico__ic{width:40px;height:40px;border-radius:10px;background:var(--hub-soft)}
.hub-apico--wm .hub-apico__ic{background:linear-gradient(135deg,#dbeafe,#93c5fd)}
.hub-apico--rf .hub-apico__ic{background:linear-gradient(135deg,#e0f2fe,#7dd3fc)}
.hub-apico--ac .hub-apico__ic{background:linear-gradient(135deg,#cffafe,#22d3ee)}
.hub-apico--mw .hub-apico__ic{background:linear-gradient(135deg,#fef3c7,#fcd34d)}
.hub-apico--tv .hub-apico__ic{background:linear-gradient(135deg,#ede9fe,#a78bfa)}
.hub-apico--mw{grid-column:1}
.hub-apico--tv{grid-column:2}
.hub-stats{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin:0 0 2.5rem}
@media(max-width:720px){.hub-stats{grid-template-columns:repeat(2,1fr)}}
@media(max-width:400px){.hub-stats{grid-template-columns:1fr}}
.hub-stats__item{background:var(--hub-card);border:1px solid var(--hub-line);border-radius:var(--hub-radius);padding:1.1rem .85rem;text-align:center;box-shadow:0 4px 16px rgba(15,23,42,.04)}
.hub-stats__item strong{display:block;font-size:1.35rem;font-weight:800;color:var(--hub);letter-spacing:-.02em;line-height:1.1}
.hub-stats__item span{display:block;font-size:.72rem;color:var(--hub-muted);margin-top:.35rem;text-transform:uppercase;letter-spacing:.04em}
.hub-block{margin:0 0 2.75rem}
.hub-block--soft{background:#f8fafc;border:1px solid var(--hub-line);border-radius:var(--hub-radius);padding:clamp(1.25rem,3vw,1.75rem)}
.hub-block__head{margin-bottom:1.25rem;text-align:center;max-width:40rem;margin-left:auto;margin-right:auto;margin-bottom:1.25rem}
.hub-h2{font-size:clamp(1.35rem,2.8vw,1.75rem);font-weight:800;margin:0 0 .5rem;letter-spacing:-.02em}
.hub-deck{margin:0;color:var(--hub-muted);font-size:.95rem;line-height:1.55}
.hub-deck--center{text-align:center;max-width:36rem;margin-left:auto;margin-right:auto}
.hub-svc-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:1rem;margin-top:1.5rem}
.hub-card{background:var(--hub-card);border:1px solid var(--hub-line);border-radius:var(--hub-radius);padding:1.15rem 1.1rem 1.25rem;position:relative;box-shadow:0 4px 20px rgba(15,23,42,.04);transition:box-shadow .2s,transform .2s}
.hub-card:hover{box-shadow:0 12px 32px rgba(37,99,235,.1);transform:translateY(-2px)}
.hub-card--wide{grid-column:1/-1}
@media(min-width:700px){.hub-card--wide .hub-card__list--cols{columns:2;column-gap:1.5rem}}
.hub-card--featured{border-color:#bfdbfe;box-shadow:0 4px 20px rgba(37,99,235,.08)}
.hub-card__badge{position:absolute;top:12px;right:12px;font-size:.62rem;font-weight:800;text-transform:uppercase;letter-spacing:.06em;background:linear-gradient(90deg,var(--hub),#7c3aed);color:#fff;padding:.25rem .5rem;border-radius:6px}
.hub-card__badge--alt{background:linear-gradient(90deg,#0891b2,var(--hub))}
.hub-card__top{display:flex;align-items:center;gap:12px;margin-bottom:.75rem}
.hub-card__icon{width:48px;height:48px;border-radius:12px;flex-shrink:0}
.hub-card__icon--wm{background:linear-gradient(135deg,#93c5fd,#3b82f6)}
.hub-card__icon--rf{background:linear-gradient(135deg,#7dd3fc,#0ea5e9)}
.hub-card__icon--ac{background:linear-gradient(135deg,#22d3ee,#0891b2)}
.hub-card__icon--mw{background:linear-gradient(135deg,#fcd34d,#f59e0b)}
.hub-card__icon--tv{background:linear-gradient(135deg,#c4b5fd,#7c3aed)}
.hub-card__title{margin:0;font-size:1.05rem;font-weight:800}
.hub-card__list{margin:0 0 1rem;padding-left:1.15rem;color:var(--hub-muted);font-size:.88rem;line-height:1.55}
.hub-card__list li{margin-bottom:.35rem}
.hub-card__call{display:inline-block;font-weight:700;font-size:.88rem;text-decoration:none;color:var(--hub)}
.hub-card__call:hover{text-decoration:underline}
.hub-checklist{margin:.75rem 0 0;padding-left:1.2rem;color:var(--hub-muted);font-size:.92rem;line-height:1.6}
.hub-checklist li{margin-bottom:.4rem}
.hub-steps{display:grid;grid-template-columns:repeat(4,1fr);gap:1rem;list-style:none;padding:0;margin:1.5rem 0 0;counter-reset:none}
@media(max-width:900px){.hub-steps{grid-template-columns:repeat(2,1fr)}}
@media(max-width:480px){.hub-steps{grid-template-columns:1fr}}
.hub-steps__item{background:var(--hub-card);border:1px solid var(--hub-line);border-radius:var(--hub-radius);padding:1rem;text-align:center;box-shadow:0 2px 12px rgba(15,23,42,.04)}
.hub-steps__n{display:flex;align-items:center;justify-content:center;width:36px;height:36px;border-radius:50%;background:var(--hub-soft);color:var(--hub);font-weight:800;margin:0 auto .5rem;font-size:1rem}
.hub-steps__item strong{display:block;font-size:.95rem;margin-bottom:.25rem}
.hub-steps__item span{display:block;font-size:.8rem;color:var(--hub-muted);line-height:1.45}
.hub-why{display:grid;grid-template-columns:repeat(4,1fr);gap:1rem;margin-top:1.25rem}
@media(max-width:900px){.hub-why{grid-template-columns:repeat(2,1fr)}}
@media(max-width:500px){.hub-why{grid-template-columns:1fr}}
.hub-why__item{background:var(--hub-card);border:1px solid var(--hub-line);border-radius:12px;padding:1rem}
.hub-why__item strong{display:block;font-size:.95rem;margin-bottom:.35rem;color:var(--hub2)}
.hub-why__item p{margin:0;font-size:.82rem;color:var(--hub-muted);line-height:1.5}
.hub-chips{display:flex;flex-wrap:wrap;gap:8px;margin-top:1rem}
.hub-chip{display:inline-block;padding:.4rem .75rem;background:#fff;border:1px solid var(--hub-line);border-radius:999px;font-size:.78rem;font-weight:600;color:var(--hub-muted)}
.hub-brands{display:flex;flex-wrap:wrap;gap:10px;margin-top:1rem}
.hub-brands a{display:inline-block;padding:.55rem 1rem;background:var(--hub-card);border:1px solid var(--hub-line);border-radius:10px;font-weight:700;font-size:.85rem;text-decoration:none;color:var(--hub2);transition:background .15s,border-color .15s}
.hub-brands a:hover{border-color:var(--hub);background:var(--hub-soft)}
.hub-cta{background:linear-gradient(120deg,var(--hub2),var(--hub),#4f46e5);border-radius:calc(var(--hub-radius) + 4px);padding:clamp(1.5rem,4vw,2.25rem);margin:2.5rem 0;text-align:center;box-shadow:0 16px 48px rgba(37,99,235,.25)}
.hub-cta__inner{max-width:32rem;margin:0 auto}
.hub-cta__title{color:#fff;font-size:clamp(1.25rem,3vw,1.6rem);font-weight:800;margin:0 0 .35rem}
.hub-cta__text{color:rgba(255,255,255,.88);margin:0 0 1rem;font-size:.95rem}
.hub-formbox{background:var(--hub-card);border:1px solid var(--hub-line);border-radius:var(--hub-radius);padding:clamp(1rem,3vw,1.5rem);margin-top:1rem;box-shadow:0 8px 28px rgba(15,23,42,.06)}
.hub-mini{text-align:center;font-size:.72rem;color:#94a3b8;margin:2rem 0 .6rem}
.hub-disclaimer{font-size:.75rem;color:#57534e;line-height:1.55;padding:1rem 1.1rem;border-radius:12px;border:1px dashed #cbd5e1;background:#f8fafc}
#hub-book,#hub-services,#hub-steps,#hub-brands{scroll-margin-top:min(110px,18vh)}
